START TRANSACTION;

SET @epic_art_storage_key = '52666df4028d1c26b77dfda2ab65accb8ae58d9f4fcf17bd0f7d00db3882828a';

INSERT INTO trophy_art (
  storage_key,
  image_url,
  image_bytes,
  created_at,
  updated_at
) VALUES (
  @epic_art_storage_key,
  NULL,
  FROM_BASE64(''),
  NOW(6),
  NOW(6)
)
ON DUPLICATE KEY UPDATE
  image_url = VALUES(image_url),
  image_bytes = VALUES(image_bytes),
  updated_at = VALUES(updated_at);

SET @epic_art_id = (
  SELECT id
  FROM trophy_art
  WHERE storage_key = @epic_art_storage_key
  ORDER BY id
  LIMIT 1
);

-- Replace main trophy art for all existing EPIC trophies.
UPDATE trophy
SET art_id = @epic_art_id
WHERE rarity = 'EPIC'
  AND @epic_art_id IS NOT NULL;

-- Replace main art for EPIC catalog entries so future generated trophies inherit it.
UPDATE trophy_catalog
SET art_id = @epic_art_id
WHERE rarity = 'EPIC'
  AND @epic_art_id IS NOT NULL;

