SELECT
  @epic_art_storage_key AS storage_key,
  @epic_art_id AS art_id,
  (SELECT COUNT(*) FROM trophy WHERE rarity = 'EPIC' AND art_id = @epic_art_id) AS epic_trophy_rows_using_new_art,
  (SELECT COUNT(*) FROM trophy_catalog WHERE rarity = 'EPIC' AND art_id = @epic_art_id) AS epic_catalog_rows_using_new_art;

